import { afterAll, describe, expect, it, test } from "bun:test";
import { createClickHouseExecutor } from "@chkit/clickhouse";
import { ingestFlickClaudeSessions } from "../generated/chkit-ingest.js";
import type { FlickClaudeSessionsRow } from "../generated/chkit-types.js";

const testId = `test_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const baseExecutor = createClickHouseExecutor({
	url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
	username:
		process.env.CLICKHOUSE_USERNAME || process.env.CLICKHOUSE_USER || "default",
	password: process.env.CLICKHOUSE_PASSWORD || "",
	database: "default",
});

// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
const executor: typeof baseExecutor = {
	...baseExecutor,
	async insert(params) {
		const rows = params.values
			.map((r: Record<string, unknown>) => JSON.stringify(r))
			.join("\n");
		await baseExecutor.execute(
			`INSERT INTO ${params.table} FORMAT JSONEachRow ${rows}`,
		);
	},
};

async function waitForQuery<T>(
	query: string,
	timeoutMs = 30000,
	intervalMs = 2000,
): Promise<T[]> {
	const start = Date.now();
	while (Date.now() - start < timeoutMs) {
		try {
			const results = await executor.query<T>(query);
			if (results.length > 0) return results;
		} catch {
			// Transient ClickHouse errors (e.g. S3 storage) - retry
		}
		await new Promise((r) => setTimeout(r, intervalMs));
	}
	return [];
}

afterAll(() => {
	// Fire-and-forget: ClickHouse Cloud DELETE mutations are slow
	executor
		.execute(`DELETE FROM flick.claude_sessions WHERE session_id = '${testId}'`)
		.catch(() => {});
});

describe("ingestFlickClaudeSessions", () => {
	const now = new Date().toISOString().replace("Z", "");
	const row: FlickClaudeSessionsRow = {
		session_date: now,
		last_interaction_date: now,
		session_id: testId,
		organization_id: "org_test",
		project_path: "/test/project",
		repository: null,
		content: "test session content",
		subagents: {},
		skills: ["code:testing"],
		slash_commands: [],
		subagent_types: [],
		ingested_at: now,
		user_id: "user_test",
		git_branch: "main",
		git_sha: null,
		input_tokens: "100",
		output_tokens: "200",
		cache_read_input_tokens: "0",
		cache_creation_input_tokens: "0",
		total_tokens: "300",
		tag: "integration-test",
	};

	test("inserts a row and reads it back", async () => {
		await ingestFlickClaudeSessions(executor, [row]);

		const results = await waitForQuery<{
			session_id: string;
			tag: string;
		}>(
			`SELECT session_id, tag FROM flick.claude_sessions WHERE session_id = '${testId}' LIMIT 1`,
		);

		expect(results).toHaveLength(1);
		expect(results[0]?.session_id).toBe(testId);
		expect(results[0]?.tag).toBe("integration-test");
	}, 45000);

	it("rejects invalid data with validate option", async () => {
		const badRow = {
			...row,
			input_tokens: 999,
		} as unknown as FlickClaudeSessionsRow;
		expect(
			ingestFlickClaudeSessions(executor, [badRow], { validate: true }),
		).rejects.toThrow();
	});
});

import { describe, expect, it } from "bun:test";
import { FlickClaudeSessionsRowSchema } from "../generated/chkit-types.js";

describe("FlickClaudeSessionsRowSchema", () => {
	const validRow = {
		session_date: "2026-02-13T09:24:27.180Z",
		last_interaction_date: "2026-02-13T09:24:27.180Z",
		session_id: "sess_abc123",
		organization_id: "org_xyz",
		project_path: "/Users/dev/project",
		repository: "github.com/org/repo",
		content: "session transcript content",
		subagents: { agent1: "result1" },
		skills: ["code:testing"],
		slash_commands: ["/commit"],
		subagent_types: ["Explore"],
		ingested_at: "2026-02-13T09:24:27.180Z",
		user_id: "user_123",
		git_branch: "main",
		git_sha: "abc123def456",
		input_tokens: "1000",
		output_tokens: "2000",
		cache_read_input_tokens: "500",
		cache_creation_input_tokens: "100",
		total_tokens: "3600",
		tag: "production",
	};

	it("parses a valid row", () => {
		const result = FlickClaudeSessionsRowSchema.parse(validRow);
		expect(result.session_id).toBe("sess_abc123");
		expect(result.organization_id).toBe("org_xyz");
		expect(result.skills).toEqual(["code:testing"]);
		expect(result.subagents).toEqual({ agent1: "result1" });
	});

	it("accepts null for nullable fields", () => {
		const row = {
			...validRow,
			repository: null,
			git_branch: null,
			git_sha: null,
			tag: null,
		};
		const result = FlickClaudeSessionsRowSchema.parse(row);
		expect(result.repository).toBeNull();
		expect(result.git_branch).toBeNull();
		expect(result.git_sha).toBeNull();
		expect(result.tag).toBeNull();
	});

	it("rejects missing required fields", () => {
		const { session_id: _, ...incomplete } = validRow;
		expect(() => FlickClaudeSessionsRowSchema.parse(incomplete)).toThrow();
	});

	it("rejects wrong types", () => {
		expect(() =>
			FlickClaudeSessionsRowSchema.parse({ ...validRow, input_tokens: 1000 }),
		).toThrow();
	});
});

